import 'dart:async';
import 'dart:io';

/// File-based sequential logger. Writes to `%TEMP%\NetDiagnostic\debug.log`
/// (or `/tmp/NetDiagnostic/debug.log` on Linux/Mac).  Does NOT depend on
/// Flutter (no `path_provider`) so it works in standalone `dart run`.
class AppLogger {
  static File? _file;
  static final _queue = <String>[];
  static bool _writing = false;

  static String get _tempDir {
    if (Platform.isWindows) {
      return '${Platform.environment['TEMP'] ?? Platform.environment['TMP'] ?? '.'}\\NetDiagnostic';
    }
    return '/tmp/NetDiagnostic';
  }

  static void _enqueue(String message) {
    _queue.add(message);
    if (!_writing) _flush();
  }

  static Future<void> _flush() async {
    if (_writing) return;
    _writing = true;
    try {
      if (_file == null) {
        final dir = Directory(_tempDir);
        if (!await dir.exists()) await dir.create(recursive: true);
        _file = File('${dir.path}/debug.log');
      }
      while (_queue.isNotEmpty) {
        await _file!
            .writeAsString('${_queue.removeAt(0)}\n', mode: FileMode.append);
      }
    } catch (_) {
    } finally {
      _writing = false;
    }
  }

  static String _ts() => DateTime.now().toIso8601String().substring(11, 23);

  static void info(String msg) => _enqueue('[${_ts()}] INFO  $msg');
  static void event(String msg) => _enqueue('[${_ts()}] EVENT $msg');
  static void error(String msg) => _enqueue('[${_ts()}] ERROR $msg');
  static void warn(String msg) => _enqueue('[${_ts()}] WARN  $msg');
}

