/// Default test targets used by diagnostics.
///
/// These are chosen for accessibility in mainland China:
/// - [connectivityHost] — Alibaba public DNS (223.5.5.5), reliable ICMP responder
/// - [trustedDns] — same, for DNS pollution reference queries
/// - [dnsTestDomains] — major Chinese domains for pollution detection
/// - [speedTestUrl] — homepage download for speed estimation
///
/// Override via settings or SharedPreferences for other regions.
class TestTargets {
  TestTargets._();

  /// Default host for ping / internet connectivity checks.
  static const String connectivityHost = '223.5.5.5';

  /// Trusted public DNS server (used as reference for DNS pollution detection).
  static const String trustedDns = '223.5.5.5';

  /// Domains checked during DNS pollution detection.
  static const List<String> dnsTestDomains = [
    'aliyun.com',
    'qq.com',
    'baidu.com',
  ];

  /// URL used for the internet speed test (HTTP GET, measured by throughput).
  ///
  /// NOTE: A homepage download is NOT a calibrated speed-test payload.
  /// For reliable measurements a fixed-size file (≥512 KB) should be served
  /// from a CDN endpoint close to the user.  The current value is a fallback
  /// that works in mainland China without external dependencies.
  static const String speedTestUrl = 'https://www.aliyun.com';

  /// Minimum bytes that must be downloaded before a speed measurement is
  /// considered reliable.  Below this threshold the result is marked WARNING.
  static const int speedTestMinBytes = 100 * 1024; // 100 KB
}

