import 'dart:io';
import 'package:permission_handler/permission_handler.dart';
import '../../features/diagnostics/domain/entities/diagnostic_result.dart';
import '../../features/diagnostics/domain/enums/test_status.dart';
import '../../core/constants/test_ids.dart';
import '../logger.dart';

/// Result of a permission check for a diagnostic.
class PermissionCheckResult {
  final bool granted;
  final bool degraded;
  final String? degradationNote;
  final List<String> missingPermissions;

  const PermissionCheckResult({
    required this.granted,
    this.degraded = false,
    this.degradationNote,
    this.missingPermissions = const [],
  });
}

/// Service for checking and requesting permissions needed by diagnostics.
class PermissionService {
  static final PermissionService instance = PermissionService._();
  PermissionService._();

  /// Map of TestId → required permissions for the current platform.
  List<Permission> _requiredPermissions(TestId id) {
    final perms = <Permission>[];
    switch (id) {
      // WiFi tests need WiFi access on mobile
      case TestId.g1WifiDiagnostics:
        if (Platform.isAndroid) {
          perms.add(Permission.locationWhenInUse); // Android 8+ WiFi scanning
        }
        break;
      // DNS tests need network access (generally granted by default)
      case TestId.g3DnsServers:
      case TestId.g3DnsPollution:
      case TestId.g3InternetConnectivity:
      case TestId.g4DnsResolution:
      case TestId.g4Ping:
      case TestId.g4Traceroute:
        // Network access is implicit — no special permission needed
        break;
      default:
        break;
    }
    return perms;
  }

  /// Check if permissions for a given diagnostic are granted.
  /// Returns [PermissionCheckResult] with grant status and degradation info.
  Future<PermissionCheckResult> checkPermissions(TestId id) async {
    final required = _requiredPermissions(id);
    if (required.isEmpty) {
      return const PermissionCheckResult(granted: true);
    }

    final missing = <String>[];
    var allGranted = true;

    for (final perm in required) {
      final status = await perm.status;
      if (!status.isGranted) {
        allGranted = false;
        missing.add(perm.toString());
      }
    }

    if (allGranted) {
      return const PermissionCheckResult(granted: true);
    }

    // Some permissions missing — return degraded
    return PermissionCheckResult(
      granted: false,
      degraded: true,
      degradationNote: missing.isNotEmpty
          ? 'Missing permissions: ${missing.join(", ")}. '
              'The diagnostic may return limited results.'
          : null,
      missingPermissions: missing,
    );
  }

  /// Check whether a diagnostic can run at all (even in degraded mode).
  Future<bool> canRunDiagnostic(TestId id) async {
    // Most diagnostics can run without special permissions on desktop
    if (!Platform.isAndroid && !Platform.isIOS) return true;

    // On mobile, check if at least network is available
    final required = _requiredPermissions(id);
    if (required.isEmpty) return true;

    for (final perm in required) {
      final status = await perm.status;
      if (status.isPermanentlyDenied) return false;
    }
    return true;
  }

  /// Apply permission status to a [DiagnosticResult].
  DiagnosticResult applyPermissionResult(
    DiagnosticResult result,
    PermissionCheckResult permResult,
  ) {
    if (permResult.granted || !permResult.degraded) return result;

    return result.copyWith(
      status: result.status == TestStatus.pass
          ? TestStatus.warning
          : result.status,
      summary: '${result.summary} (degraded — permissions limited)',
      details: '${result.details}\n\n'
          '⚠ Permission note: ${permResult.degradationNote ?? "Some permissions were not granted."}',
    );
  }
}

