import '../logger.dart';

/// Maps Dart [TestId] to C [NdDiagnosticId] (nd_types.h).
/// Both enums use the same index values — verify when adding new tests.
int _toNativeId(TestId id) {
  switch (id) {
    // G1
    case TestId.g1NetworkAdapters:    return 0;
    case TestId.g1NicAdvanced:        return 1;
    case TestId.g1WifiDiagnostics:    return 2;
    case TestId.g1WiredDiagnostics:   return 3;
    case TestId.g1DhcpStatus:         return 4;
    case TestId.g1IpConfiguration:    return 5;
    case TestId.g1ActiveConnections:  return 6;
    // G2
    case TestId.g2NetworkProfile:     return 7;
    case TestId.g2TcpSettings:        return 8;
    case TestId.g2DefaultGateway:     return 9;
    case TestId.g2RoutingTable:       return 10;
    case TestId.g2ArpTable:           return 11;
    case TestId.g2ProxySettings:      return 12;
    // G3
    case TestId.g3NetskopeStatus:     return 13;
    case TestId.g3DnsServers:         return 14;
    case TestId.g3DnsCache:           return 15;
    case TestId.g3DnsPollution:       return 16;
    case TestId.g3InternetConnectivity: return 17;
    case TestId.g3InternetSpeedTest:  return 18;
    // G4
    case TestId.g4DnsResolution:      return 19;
    case TestId.g4Ping:               return 20;
    case TestId.g4Traceroute:         return 21;
    case TestId.g4PathPing:           return 22;
    case TestId.g4MtuDiscovery:       return 23;
    case TestId.g4PortScan:           return 24;
    // G5
    case TestId.g5TcpConnect:         return 25;
    case TestId.g5ServiceBanner:      return 26;
    case TestId.g5FtpDiagnostics:     return 27;
    case TestId.g5SshDiagnostics:     return 28;
    case TestId.g5EmailDiagnostics:   return 29;
    // G5 HTTP tests (no C native — handled in Dart)
    case TestId.g5UrlParsing:
    case TestId.g5CurlVerbose:
    case TestId.g5HttpHeaders:
    case TestId.g5SecurityHeaders:
    case TestId.g5SslCertificate:
    case TestId.g5HttpRedirect:
    case TestId.g5HttpCompression:
    case TestId.g5HttpTiming:
      return -1; // Dart-only
  }
}

/// Convert C [NdStatus] to Dart [TestStatus].
TestStatus _toDartStatus(int nativeStatus) {
  switch (nativeStatus) {
    case 0: return TestStatus.pass;
    case 1: return TestStatus.warning;
    case 2: return TestStatus.fail;
    case 3: return TestStatus.skipped;
    case 4: return TestStatus.error;
    case 5: return TestStatus.info;
    default: return TestStatus.error;
  }
}

/// Service wrapping the C++ native diagnostic plugin via dart:ffi.
///
/// Usage:
/// ```dart
/// final svc = NativeDiagnosticService.instance;
/// svc.initialize();
/// if (svc.isAvailable) {
///   final result = await svc.runDiagnostic(TestId.g1NetworkAdapters);
/// }
/// ```
class NativeDiagnosticService {
  static final NativeDiagnosticService instance = NativeDiagnosticService._();
  NativeDiagnosticService._();

  bool _initialized = false;

  /// Whether the native plugin library loaded and initialized successfully.
  bool get isAvailable => _initialized;

  String _version = '';

  /// Plugin version string.
  String get version => _version;

  /// Initialize the native plugin. Safe to call multiple times.
  /// Returns true on success, false if the native library is unavailable.
  bool initialize() {
    if (_initialized) return true;
    if (!ffi.isAvailable) {
      AppLogger.event('[NativeSvc] Native plugin library not found — '
          'diagnostics will use Dart fallback');
      return false;
    }
    try {
      ffi.NdPlugin.instance.initialize();
      _version = ffi.NdPlugin.instance.version;
      _initialized = true;
      AppLogger.event('[NativeSvc] Native plugin initialized — v$_version');
      return true;
    } catch (e) {
      AppLogger.event('[NativeSvc] Failed to initialize native plugin: $e');
      return false;
    }
  }

  /// Shutdown the native plugin and release resources.
  void shutdown() {
    if (!_initialized) return;
    ffi.NdPlugin.instance.shutdown();
    _initialized = false;
  }

  /// Check whether a given diagnostic is supported natively.
  /// G5 HTTP/protocol tests are always Dart-only.
  bool isNativeCapable(TestId id) {
    return _toNativeId(id) >= 0;
  }

  /// Run a diagnostic via the C++ native plugin.
  ///
  /// Returns null if the plugin is unavailable or the diagnostic is
  /// not implemented natively (caller should fall back to Dart).
  DiagnosticResult? runDiagnostic(TestId id, {String? target}) {
    final nativeId = _toNativeId(id);
    if (nativeId < 0 || !_initialized) return null;

    try {
      final nativeResult = ffi.NdPlugin.instance.runDiagnostic(
        diagnosticId: nativeId,
        target: target,
      );
      if (nativeResult == null) return null;

      // ND_ERR_NOT_SUPPORTED (4) → not implemented on this platform → let Dart try
      if (nativeResult.errorCode == 4) return null;

      final props = nativeResult.properties
          .map((p) => ResultProperty(label: p.label, value: p.value))
          .toList();

      return DiagnosticResult(
        id: id,
        displayName: id.labelKey, // resolved to localized name by UI layer
        group: id.group,
        status: _toDartStatus(nativeResult.status),
        summary: nativeResult.summary,
        details: nativeResult.details,
        duration: Duration(microseconds: nativeResult.durationUs),
        properties: props,
        rawOutput: nativeResult.rawOutput,
      );
    } catch (e) {
      AppLogger.event('[NativeSvc] Native diagnostic $id failed: $e');
      return null; // caller falls back to Dart
    }
  }
}

import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/result_property.dart';

/// Immutable model for the outcome of one diagnostic test invocation.
///
/// Each [DiagnosticResult] carries the test identity, a human-readable summary,
/// detailed output, timing information, and optional structured properties.
class DiagnosticResult {
  final TestId id;
  final String displayName;
  final TestGroup group;
  final TestStatus status;
  final String summary;
  final String details;
  final Duration duration;
  final DateTime timestamp;
  final List<ResultProperty> properties;
  final String? rawOutput;
  final String? errorOutput;

  DiagnosticResult({
    required this.id,
    required this.displayName,
    required this.group,
    required this.status,
    this.summary = '',
    this.details = '',
    this.duration = Duration.zero,
    DateTime? timestamp,
    this.properties = const [],
    this.rawOutput,
    this.errorOutput,
  }) : timestamp = timestamp ?? DateTime.now();

  // ---------------------------------------------------------------------------
  // Convenience getters
  // ---------------------------------------------------------------------------

  bool get isPass => status == TestStatus.pass;
  bool get isFail => status == TestStatus.fail;
  bool get isWarning => status == TestStatus.warning;
  bool get isSkipped => status == TestStatus.skipped;
  bool get isError => status == TestStatus.error;

  /// A single-character icon representing the status.
  String get statusIcon {
    switch (status) {
      case TestStatus.pass:
        return '✓'; // ✓
      case TestStatus.fail:
        return '✕'; // ✕
      case TestStatus.warning:
        return '!';
      case TestStatus.skipped:
        return '·'; // ·
      case TestStatus.error:
        return 'E';
      case TestStatus.info:
        return 'i';
    }
  }

  // ---------------------------------------------------------------------------
  // copyWith
  // ---------------------------------------------------------------------------

  DiagnosticResult copyWith({
    TestId? id,
    String? displayName,
    TestGroup? group,
    TestStatus? status,
    String? summary,
    String? details,
    Duration? duration,
    DateTime? timestamp,
    List<ResultProperty>? properties,
    String? Function()? rawOutput,
    String? Function()? errorOutput,
  }) {
    return DiagnosticResult(
      id: id ?? this.id,
      displayName: displayName ?? this.displayName,
      group: group ?? this.group,
      status: status ?? this.status,
      summary: summary ?? this.summary,
      details: details ?? this.details,
      duration: duration ?? this.duration,
      timestamp: timestamp ?? this.timestamp,
      properties: properties ?? this.properties,
      rawOutput: rawOutput != null ? rawOutput() : this.rawOutput,
      errorOutput: errorOutput != null ? errorOutput() : this.errorOutput,
    );
  }

  // ---------------------------------------------------------------------------
  // Serialization
  // ---------------------------------------------------------------------------

  Map<String, dynamic> toJson() => {
        'id': id.name,
        'displayName': displayName,
        'group': group.name,
        'status': status.name,
        'summary': summary,
        'details': details,
        'durationMs': duration.inMilliseconds,
        'timestamp': timestamp.toIso8601String(),
        'properties': properties.map((p) => p.toJson()).toList(),
        'rawOutput': rawOutput,
        'errorOutput': errorOutput,
      };
}

/// How important a single property value is when presenting results.
enum ResultPropertySeverity { info, warning, error }

/// A single property in a diagnostic test result.
///
/// Properties are rich key-value pairs with an optional severity level
/// and optional child properties for nested data (e.g. a list of hops
/// in a traceroute).
class ResultProperty {
  final String label;
  final String value;
  final ResultPropertySeverity severity;
  final List<ResultProperty>? children;

  const ResultProperty({
    required this.label,
    required this.value,
    this.severity = ResultPropertySeverity.info,
    this.children,
  });

  Map<String, dynamic> toJson() => {
        'label': label,
        'value': value,
        'severity': severity.name,
        if (children != null)
          'children': children!.map((c) => c.toJson()).toList(),
      };
}

/// Status of a single diagnostic test execution.
enum TestStatus {
  pass,
  fail,
  warning,
  error,
  skipped,
  info,
}

