// ---------------------------------------------------------------------------
// ProcessResult -- universal command result container
// ---------------------------------------------------------------------------

/// Result from running a platform command.
///
/// Encapsulates stdout, stderr, exit code, and timeout state so callers
/// can handle errors uniformly regardless of platform.
class ProcessResult {
  final String stdout;
  final String stderr;
  final int exitCode;
  final bool timedOut;

  const ProcessResult({
    required this.stdout,
    required this.stderr,
    required this.exitCode,
    this.timedOut = false,
  });

  /// Returns true when the command completed successfully and did not time out.
  bool get isSuccess => exitCode == 0 && !timedOut;
}

// ---------------------------------------------------------------------------
// PlatformCommand -- abstract strategy
// ---------------------------------------------------------------------------

/// Abstract strategy for executing OS-native commands.
///
/// Each platform (Windows, macOS, Linux, Android, iOS) provides its own
/// implementation.  The [MockSimulatorPlatformCommand] supplies staged
/// responses so the app can be demonstrated without real hardware.
///
/// ## Core methods
///
/// *   **`runStream`** -- Spawns a process and yields stdout / stderr lines
///     as a live stream.  Used by tests that show real-time progress (ping,
///     traceroute).
/// *   **`runAndWait`** -- Spawns a process and collects the full result
///     after it exits (or times out).  Used by one-shot tests (DNS lookup,
///     port scan).
/// *   **`findExecutable`** -- Locates an executable on the current $PATH
///     (or equivalent).
/// *   **`shellExecutable` / `shellArguments`** -- Return the shell binary
///     and the flags needed to run an arbitrary command string.
///
/// ## Error handling
///
/// All errors (timeout, process not found, permission denied, etc.) are
/// captured and returned as a [ProcessResult] with a non-zero exit code
/// and a human-readable message in [ProcessResult.stderr].  **No exceptions
/// are thrown from public API surface.**
abstract class PlatformCommand {
  /// Run [executable] with [arguments] and yield stdout lines as a stream.
  ///
  /// Stdout and stderr are merged into a single stream so the consumer sees
  /// output in the approximate order it was produced.
  ///
  /// If the process does not complete within [timeout] it is killed and the
  /// stream yields one final line indicating the timeout before closing.
  Stream<String> runStream({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
    String? workingDirectory,
  });

  /// Run [executable] with [arguments] and wait for completion.
  ///
  /// Returns a [ProcessResult] that is guaranteed to be non-null.  On
  /// timeout the process is killed and [ProcessResult.timedOut] is true.
  Future<ProcessResult> runAndWait({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
  });

  /// Locate [name] on this platform's executable search path.
  ///
  /// Returns the first matching absolute path, or `null` when the
  /// executable cannot be found.
  Future<String?> findExecutable(String name);

  /// The shell binary to use when running shell scripts.
  ///
  /// Examples: `powershell.exe` on Windows, `/bin/zsh` on macOS.
  String get shellExecutable;

  /// The argument list needed to pass [command] to [shellExecutable].
  ///
  /// Example: `['-NoProfile', '-Command', command]` for PowerShell.
  List<String> shellArguments(String command);
}

