/// Port scan config: checkbox for common ports + custom range inputs.
///
/// - Checkbox: "Scan common ports" (25 well-known ports)
/// - From / To: custom port range (if both > 0 and from ≤ to)
/// - Both are combined with automatic deduplication.
class PortScanConfig extends ConsumerWidget {
  const PortScanConfig({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final runState = ref.watch(diagnosticRunProvider);
    final isRunning = runState.runStatus == RunStatus.running;
    final scanCommon = ref.watch(portScanCommonProvider);
    final from = ref.watch(portScanFromProvider);
    final to = ref.watch(portScanToProvider);

    return Container(
      margin: const EdgeInsets.symmetric(horizontal: 12),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: AppTheme.bgCard.withValues(alpha: 0.5),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: AppTheme.accentBlue.withValues(alpha: 0.3)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(children: [
            Icon(Icons.portable_wifi_off, size: 14, color: AppTheme.accentBlue),
            const SizedBox(width: 6),
            Text('Port Scan', style: _labelStyle(AppTheme.accentBlue)),
          ]),
          const SizedBox(height: 6),

          // Common ports checkbox
          Row(children: [
            SizedBox(
              width: 20,
              height: 20,
              child: Checkbox(
                value: scanCommon,
                onChanged: isRunning
                    ? null
                    : (v) {
                        ref.read(portScanCommonProvider.notifier).state =
                            v ?? true;
                      },
                activeColor: AppTheme.cyan,
                materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
                visualDensity: VisualDensity.compact,
              ),
            ),
            const SizedBox(width: 6),
            Text('Scan Common Ports', style: _smallText(AppTheme.textPrimary)),
          ]),
          const SizedBox(height: 8),

          // Custom range
          Row(children: [
            Icon(Icons.tune, size: 12, color: AppTheme.textSecondary),
            const SizedBox(width: 4),
            Text('Range:', style: _smallText(AppTheme.textSecondary)),
          ]),
          const SizedBox(height: 4),
          Row(children: [
            Expanded(
              child: _PortField(
                label: 'From',
                value: from,
                enabled: !isRunning,
                onChanged: (v) {
                  ref.read(portScanFromProvider.notifier).state =
                      v.clamp(0, 65535);
                },
              ),
            ),
            const SizedBox(width: 8),
            Text('–',
                style: TextStyle(color: AppTheme.textSecondary, fontSize: 13)),
            const SizedBox(width: 8),
            Expanded(
              child: _PortField(
                label: 'To',
                value: to,
                enabled: !isRunning,
                onChanged: (v) {
                  ref.read(portScanToProvider.notifier).state =
                      v.clamp(0, 65535);
                },
              ),
            ),
          ]),
          // Validation hint
          if (from > 0 && to > 0 && from > to)
            Padding(
              padding: const EdgeInsets.only(top: 4),
              child: Text('From Must Be ≤ To',
                  style: _smallText(AppTheme.failRed)),
            ),
        ],
      ),
    );
  }
}

