import 'dart:async';
import 'dart:io';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/result_property.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';
import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_command.dart';
import 'g4_base.dart';
import 'g4_remote_host.dart' as g4;

/// Platform-agnostic G4 — delegates to existing functions with logging.
class G4RemoteHostAdapter extends G4RemoteHostBase {
  const G4RemoteHostAdapter();

  @override
  Future<DiagnosticResult> dnsResolution(
      {required String target, required PlatformCommand cmd}) async {
    log('dnsResolution — target=$target');
    return g4.dnsResolution(target: target, cmd: cmd);
  }

  @override
  Future<DiagnosticResult> ping(
      {required String target, required PlatformCommand cmd}) async {
    log('ping — target=$target');
    return g4.ping(target: target, cmd: cmd);
  }

  @override
  Future<DiagnosticResult> traceroute(
      {required String target, required PlatformCommand cmd}) async {
    log('traceroute — target=$target');
    return g4.traceroute(target: target, cmd: cmd);
  }

  @override
  Future<DiagnosticResult> pathPing(
      {required String target, required PlatformCommand cmd}) async {
    log('pathPing — target=$target');
    return g4.pathPing(target: target, cmd: cmd);
  }

  @override
  Future<DiagnosticResult> mtuDiscovery(
      {required String target, required PlatformCommand cmd}) async {
    log('mtuDiscovery — target=$target');
    return g4.mtuDiscovery(target: target, cmd: cmd);
  }

  // -- Port Scan ----------------------------------------------------------------

  /// Well-known ports to scan in "common" mode.
  static const _commonPorts = [
    21,
    22,
    23,
    25,
    53,
    80,
    110,
    135,
    139,
    143,
    443,
    445,
    993,
    995,
    1433,
    1521,
    1723,
    3306,
    3389,
    5432,
    5900,
    6379,
    8080,
    8443,
    27017,
  ];

  @override
  Future<DiagnosticResult> portScan({
    required String target,
    required PlatformCommand cmd,
    int? fromPort,
    int? toPort,
  }) async {
    log('portScan — target=$target from=$fromPort to=$toPort');
    final sw = Stopwatch()..start();
    final props = <ResultProperty>[];

    // Build port set:
    // - both null → scan common ports only
    // - custom range set → scan ONLY the custom range (common ports are
    //   controlled by the separate checkbox in the UI; runAll() won't call
    //   portScan with fromPort set unless the user wants a range scan)
    final Set<int> ports = {};
    final bool hasCustom = fromPort != null && toPort != null;

    if (hasCustom) {
      final lo = fromPort.clamp(1, 65535);
      final hi = toPort.clamp(1, 65535);
      for (int p = lo > hi ? hi : lo; p <= (lo > hi ? lo : hi); p++) {
        ports.add(p);
      }
    } else {
      // No custom range — scan common ports
      ports.addAll(_commonPorts);
    }

    if (ports.isEmpty) {
      sw.stop();
      return DiagnosticResult(
          id: TestId.g4PortScan,
          displayName: 'Port Scan',
          group: TestGroup.g4,
          status: TestStatus.warning,
          summary: 'No ports to scan',
          duration: sw.elapsed);
    }

    int open = 0, closed = 0, filtered = 0, scanned = 0;
    const concurrency = 20;
    final toScan = ports.toList()..sort();
    int idx = 0;

    Future<void> worker() async {
      while (idx < toScan.length) {
        final port = toScan[idx++];
        scanned++;
        try {
          final sock = await Socket.connect(
            target,
            port,
            timeout: const Duration(seconds: 2),
          );
          sock.destroy();
          open++;
          props.add(ResultProperty(label: 'Port $port', value: 'OPEN'));
        } on TimeoutException {
          filtered++;
        } on SocketException {
          closed++;
        } catch (_) {
          filtered++;
        }
      }
    }

    try {
      await Future.wait(List.generate(concurrency, (_) => worker()));
    } catch (_) {}

    sw.stop();
    final modeLabel = hasCustom ? 'common + $fromPort-$toPort' : 'common ports';
    return DiagnosticResult(
      id: TestId.g4PortScan,
      displayName: 'Port Scan',
      group: TestGroup.g4,
      status: open > 0 ? TestStatus.pass : TestStatus.info,
      summary: '$open open, $closed closed, $filtered filtered ($modeLabel)',
      details: 'Scanned $scanned unique ports in ${sw.elapsed.inSeconds}s',
      duration: sw.elapsed,
      properties: props,
    );
  }
}

