/// Reusable summary card widget showing pass/warn/fail/skip counts.
///
/// Uses [dashboardStatsProvider] to get the latest counts from the
/// diagnostic run state.  When no run has completed, shows zeros.
class SummaryCards extends ConsumerWidget {
  const SummaryCards({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final stats = ref.watch(dashboardStatsProvider);

    final pass = stats['pass'] ?? 0;
    final fail = stats['fail'] ?? 0;
    final warn = stats['warn'] ?? 0;
    final skip = stats['skip'] ?? 0;
    final total = stats['completed'] ?? (pass + fail + warn + skip);

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      mainAxisSize: MainAxisSize.min,
      children: [
        // Label with total
        Padding(
          padding: const EdgeInsets.only(bottom: 8),
          child: Row(children: [
            Expanded(
                child: Text(
              'Summary',
              style: TextStyle(
                  color: AppTheme.textSecondary,
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
                  letterSpacing: 0.6),
            )),
            Text('Total: $total',
                style: TextStyle(color: AppTheme.textSecondary, fontSize: 10)),
          ]),
        ),

        // Cards in a 2x2 grid
        Row(
          children: [
            Expanded(
              child: _SummaryCard(
                count: pass,
                label: 'Pass',
                color: AppTheme.passGreen,
                icon: Icons.check_circle,
              ),
            ),
            const SizedBox(width: 6),
            Expanded(
              child: _SummaryCard(
                count: warn,
                label: 'Warning',
                color: AppTheme.warnYellow,
                icon: Icons.warning_amber,
              ),
            ),
          ],
        ),
        const SizedBox(height: 6),
        Row(
          children: [
            Expanded(
              child: _SummaryCard(
                count: fail,
                label: 'Fail',
                color: AppTheme.failRed,
                icon: Icons.cancel,
              ),
            ),
            const SizedBox(width: 6),
            Expanded(
              child: _SummaryCard(
                count: skip,
                label: 'Skipped',
                color: AppTheme.skipGray,
                icon: Icons.remove_circle_outline,
              ),
            ),
          ],
        ),
      ],
    );
  }
}

