import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:net_diagnostic/features/diagnostics/presentation/providers/diagnostic_provider.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'dart:io' show Platform;

class ReportState {
  final String? htmlContent;
  final bool isGenerating;
  final String? filePath;

  const ReportState(
      {this.htmlContent, this.isGenerating = false, this.filePath});
}

class ReportNotifier extends StateNotifier<ReportState> {
  final Ref _ref;
  ReportNotifier(this._ref) : super(const ReportState());

  Future<void> generateReport(String target) async {
    state = state.copyWith(isGenerating: true);

    final diagnosticState = _ref.read(diagnosticRunProvider);
    final html = _buildHtml(target, diagnosticState.sortedResults);

    state = ReportState(htmlContent: html, isGenerating: false);
  }

  String _buildHtml(String target, List<DiagnosticResult> results) {
    final now = DateTime.now();
    final passCount = results.where((r) => r.isPass).length;
    final warnCount = results.where((r) => r.isWarning).length;
    final failCount = results.where((r) => r.isFail).length;
    final skipCount = results.where((r) => r.isSkipped).length;

    // Group by group
    final groups = <TestGroup, List<DiagnosticResult>>{};
    for (final r in results) {
      groups.putIfAbsent(r.group, () => []).add(r);
    }

    final groupSections = groups.entries.map((entry) {
      final sectionTests =
          entry.value.map((r) => _buildTestDetail(r)).join('\n');
      return '''
      <h3 style="color:#e94560;margin:20px 0 10px">${entry.key.label}</h3>
      $sectionTests
      ''';
    }).join('\n');

    return '''
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>NetDiagnostic Report - $target</title>
<style>
${_reportCss()}
</style>
</head>
<body>
<div class="header">
  <h1>Network Diagnostic Report</h1>
  <p>Generated at: ${now.toString()}</p>
  <p>Target: $target</p>
  <p>Platform: ${Platform.operatingSystem}</p>
</div>
<div class="summary">
  <h2>Executive Summary</h2>
  <div class="summary-cards">
    <div class="card pass"><span class="count">$passCount</span><span class="label">PASS</span></div>
    <div class="card warn"><span class="count">$warnCount</span><span class="label">WARN</span></div>
    <div class="card fail"><span class="count">$failCount</span><span class="label">FAIL</span></div>
