/// The top-level simulator screen.
///
/// Renders a dark-themed scaffold with an app-bar that contains:
///   - A device picker dropdown
///   - An orientation toggle button
///   - A platform badge showing the current simulated OS
///
/// The device frame auto-scales to fill the available window space and
/// supports pinch-to-zoom.  Inside the frame runs the real diagnostic app
/// backed by the host-native [PlatformCommand] for genuine network diagnostics.
class SimulatorScreen extends ConsumerStatefulWidget {
  const SimulatorScreen({super.key});

  @override
  ConsumerState<SimulatorScreen> createState() => _SimulatorScreenState();
}

class _SimulatorScreenState extends ConsumerState<SimulatorScreen> {
  final TransformationController _transformController =
      TransformationController();

  @override
  void dispose() {
    _transformController.dispose();
    super.dispose();
  }

  /// Compute the initial scale that makes the device frame fill the window.
  void _updateScale(Size viewport) {
    final state = ref.read(simulatorProvider);
    final device = state.currentDevice;
    final effectiveScreen = state.orientation == SimulatorOrientation.portrait
        ? device.screenSize
        : Size(device.screenSize.height, device.screenSize.width);
    final bh = device.bezelThickness;
    final totalW = effectiveScreen.width + bh * 2 + 48; // 48 for outer padding
    final totalH = effectiveScreen.height + bh * 2 + 48;

    if (totalW > 0 && totalH > 0 && viewport.width > 0 && viewport.height > 0) {
      final scaleX = viewport.width / totalW;
      final scaleY = viewport.height / totalH;
      final scale = (scaleX < scaleY ? scaleX : scaleY).clamp(0.3, 2.5);
      _transformController.value = Matrix4.diagonal3Values(scale, scale, 1.0);
    }
  }

  @override
  Widget build(BuildContext context) {
    final state = ref.watch(simulatorProvider);
    final device = state.currentDevice;

    return Scaffold(
      backgroundColor: const Color(0xFF2D2D2D),
      appBar: AppBar(
        title: const Text('NetDiagnostic Simulator'),
        backgroundColor: const Color(0xFF1A1A2E),
        elevation: 2,
        actions: [
          DeviceSelector(
            selected: device,
            onChanged: (d) =>
                ref.read(simulatorProvider.notifier).selectDevice(d),
          ),
          const SizedBox(width: 8),
          IconButton(
            icon: Icon(
              state.orientation == SimulatorOrientation.portrait
                  ? Icons.screen_rotation
                  : Icons.stay_current_portrait,
              color: Colors.white70,
            ),
            tooltip: 'Toggle Orientation',
            onPressed: () =>
                ref.read(simulatorProvider.notifier).toggleOrientation(),
          ),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 4),
            margin: const EdgeInsets.only(right: 12),
            decoration: BoxDecoration(
              color: OsLogo.brandColor(device.simulatedPlatform).withAlpha(40),
              borderRadius: BorderRadius.circular(4),
              border: Border.all(
                  color: OsLogo.brandColor(device.simulatedPlatform)
                      .withAlpha(80)),
            ),
            child: OsLogo(
                platform: device.simulatedPlatform,
                size: 18,
                color: Colors.white),
          ),
        ],
      ),
      body: LayoutBuilder(
        builder: (context, constraints) {
          // Auto-fit the device on size changes (e.g. window resize).
          WidgetsBinding.instance.addPostFrameCallback((_) {
            if (mounted) {
              _updateScale(Size(constraints.maxWidth, constraints.maxHeight));
            }
          });

          return InteractiveViewer(
            minScale: 0.3,
            maxScale: 2.5,
            constrained: false,
            panEnabled: false, // let taps pass through to device content
            transformationController: _transformController,
            child: Padding(
              padding: const EdgeInsets.all(24),
              child: DeviceFrame(
                device: device,
                orientation: state.orientation,
                child: _buildAppContent(ref, device),
              ),
            ),
          );
        },
      ),
    );
  }

  Widget _buildAppContent(WidgetRef ref, DeviceDefinition device) {
    final state = ref.watch(simulatorProvider);
    return _SimulatorAppHost(
      key: const ValueKey('sim_app_host'),
      simulatedTarget: state.simulatedTarget,
    );
  }
}

/// Returns the [PlatformCommand] matching the current host OS so the
/// simulator executes genuine native network commands.
PlatformCommand _hostPlatformCommand() {
  if (Platform.isWindows) return WindowsPlatformCommand();
  if (Platform.isMacOS) return MacOsPlatformCommand();
  if (Platform.isLinux) return LinuxPlatformCommand();
  // Fallback for non-desktop (shouldn't happen for simulator builds).
  return WindowsPlatformCommand();
}

/// Stable host that creates [ProviderScope] with a host-native
/// [PlatformCommand] override so the inner diagnostic app executes
/// genuine network commands on the host machine.
class _SimulatorAppHost extends StatefulWidget {
  final String simulatedTarget;
  const _SimulatorAppHost({super.key, required this.simulatedTarget});
  @override
  State<_SimulatorAppHost> createState() => _SimulatorAppHostState();
}

class _SimulatorAppHostState extends State<_SimulatorAppHost> {
  @override
  void didUpdateWidget(covariant _SimulatorAppHost oldWidget) {
    super.didUpdateWidget(oldWidget);
  }

  @override
  Widget build(BuildContext context) {
    return ProviderScope(
      key: const ValueKey('sim_inner_scope'),
      overrides: [
        platformCommandProvider.overrideWithValue(_hostPlatformCommand()),
      ],
      child: const NetDiagnosticApp(),
    );
  }
}

import 'package:flutter/material.dart';

/// Renders an OS-brand logo using Material Icons and custom painting.
///
/// Windows uses a custom-painted four-pane window icon.  All other platforms
/// use built-in Material [Icons] so no external icon package is needed.
class OsLogo extends StatelessWidget {
  final String platform;
  final double size;
  final Color? color;

  const OsLogo({
    super.key,
    required this.platform,
    this.size = 24,
    this.color,
  });

  @override
  Widget build(BuildContext context) {
    final paintColor = color ?? brandColor(platform);
    if (platform == 'windows') {
      return SizedBox(
        width: size,
        height: size,
        child: CustomPaint(
          painter: _WindowsLogoPainter(paintColor),
          size: Size(size, size),
        ),
      );
    }
    return Icon(_platformIcon, size: size, color: paintColor);
  }

  IconData get _platformIcon {
    switch (platform) {
      case 'macos':
      case 'ios':
        return Icons.apple;
      case 'linux':
        return Icons.terminal;
      case 'android':
        return Icons.android;
      default:
        return Icons.devices;
    }
  }

  /// Returns the brand colour for a platform.
  static Color brandColor(String platform) {
    switch (platform) {
      case 'windows':
        return const Color(0xFF00ADEF);
      case 'macos':
        return const Color(0xFF000000);
      case 'linux':
        return const Color(0xFFFCC624);
      case 'android':
        return const Color(0xFF3DDC84);
      case 'ios':
        return const Color(0xFF007AFF);
      default:
        return Colors.grey;
    }
  }
}

// ---------------------------------------------------------------------------
// Windows logo — four squares in a 2×2 grid
// ---------------------------------------------------------------------------

class _WindowsLogoPainter extends CustomPainter {
  final Color color;
  const _WindowsLogoPainter(this.color);

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = color
      ..style = PaintingStyle.fill;
    final gap = size.width * 0.04;
    final half = (size.width - gap) / 2;
    canvas.drawRect(Rect.fromLTWH(0, 0, half, half), paint);
    canvas.drawRect(Rect.fromLTWH(half + gap, 0, half, half), paint);
    canvas.drawRect(Rect.fromLTWH(0, half + gap, half, half), paint);
    canvas.drawRect(Rect.fromLTWH(half + gap, half + gap, half, half), paint);
  }

  @override
  bool shouldRepaint(covariant _WindowsLogoPainter old) => old.color != color;
}

import 'package:flutter/material.dart';
import 'package:net_diagnostic/features/simulator/presentation/devices/device_definitions.dart';
import 'package:net_diagnostic/features/simulator/presentation/providers/simulator_provider.dart';

/// Renders a physical device bezel around the [child] widget.
///
/// When [showBezel] is false (or the device has no bezel thickness) the child
/// is simply clipped to the device screen shape so it can be used inside a
/// custom skin or a desktop frame.
class DeviceFrame extends StatelessWidget {
  final DeviceDefinition device;
  final Widget child;
  final bool showBezel;
  final SimulatorOrientation orientation;

  const DeviceFrame({
    super.key,
    required this.device,
    required this.child,
    this.showBezel = true,
    this.orientation = SimulatorOrientation.portrait,
  });

  @override
  Widget build(BuildContext context) {
    if (!showBezel || device.bezelThickness == 0) {
      return _buildScreenOnly();
    }
    return _buildWithBezel();
  }

  /// Clip the child to the screen rectangle without any surrounding bezel.
  Widget _buildScreenOnly() {
    return _screenSizedBox(
      child: ClipRRect(
        borderRadius: _resolveBorderRadius(),
        child: child,
      ),
    );
  }

  /// Surround the screen with a bezel frame, applying the appropriate corner
  /// radius so the bezel wraps the screen cut-out naturally.
  Widget _buildWithBezel() {
    final double bh = device.bezelThickness;
    final double extraTop =
        (device.hasNotch || device.hasDynamicIsland) ? 30.0 : 0.0;

    // Compute the outer size accounting for bezel on all sides + extra notch
    // space at the top.  Uses orientation-aware screen size.
    final Size outerSize = Size(
      _effectiveScreen.width + bh * 2,
      _effectiveScreen.height + bh * 2 + extraTop,
    );

    // The bezel's outer corner radius should be slightly larger than the
    // screen's own corner radius to produce a uniform border.
    final double screenCornerRadius =
        _resolveBorderRadius().topLeft.x; // symmetrical for most devices
    final double bezelRadius = screenCornerRadius + bh;

    return Container(
      width: outerSize.width,
      height: outerSize.height,
      decoration: BoxDecoration(
        color: device.bezelColor ?? Colors.black,
        borderRadius: BorderRadius.circular(bezelRadius),
        // When a bezel image asset is available, layer it on top.
        // image: device.bezelAssetPath != null
        //     ? DecorationImage(
        //         image: AssetImage(device.bezelAssetPath!),
        //         fit: BoxFit.fill,
        //       )
        //     : null,
        boxShadow: [
          BoxShadow(
            color: Colors.black.withAlpha(80),
            blurRadius: 24,
            offset: const Offset(0, 8),
          ),
        ],
      ),
      // Extra container for the Dynamic Island / notch visual indicator
      child: Stack(
        children: [
          Center(
            child: _screenSizedBox(
              child: ClipRRect(
                borderRadius: _resolveBorderRadius(),
                child: child,
              ),
            ),
          ),
          // Dynamic Island indicator (iOS 15 Pro)
          if (device.hasDynamicIsland)
            Positioned(
              top: extraTop > 0 ? bh + 8 : bh,
              left: 0,
              right: 0,
              child: Center(
                child: Container(
                  width: 126,
                  height: 36,
                  decoration: BoxDecoration(
                    color: Colors.black,
                    borderRadius: BorderRadius.circular(18),
                  ),
                ),
              ),
            ),
          // Traditional notch pill
          if (device.hasNotch && !device.hasDynamicIsland)
            Positioned(
              top: bh,
              left: 0,
              right: 0,
              child: Center(
                child: Container(
                  width: 180,
                  height: 28,
                  decoration: const BoxDecoration(
                    color: Colors.black,
                    borderRadius: BorderRadius.only(
                      bottomLeft: Radius.circular(14),
                      bottomRight: Radius.circular(14),
                    ),
                  ),
                ),
              ),
            ),
        ],
      ),
    );
  }

  // Effective screen size accounting for orientation.
  Size get _effectiveScreen => orientation == SimulatorOrientation.portrait
      ? device.screenSize
      : Size(device.screenSize.height, device.screenSize.width);

  // -----------------------------------------------------------------------
  // Helpers
  // -----------------------------------------------------------------------

  Widget _screenSizedBox({required Widget child}) {
    return SizedBox(
      width: _effectiveScreen.width,
      height: _effectiveScreen.height,
      child: child,
    );
  }

  BorderRadius _resolveBorderRadius() {
    if (orientation == SimulatorOrientation.portrait) {
      return device.screenBorderRadius;
    }
    // Mirror the radii so the corners follow the rotated screen.
    final r = device.screenBorderRadius;
    return BorderRadius.only(
      topLeft: r.topRight,
      topRight: r.topLeft,
      bottomRight: r.bottomLeft,
      bottomLeft: r.bottomRight,
    );
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:net_diagnostic/features/simulator/presentation/devices/device_definitions.dart';
import 'package:net_diagnostic/features/simulator/presentation/widgets/os_logo.dart';

/// OS filter state for the device picker.
final _deviceFilterProvider = StateProvider<String?>((ref) => null);

/// A device picker widget that shows OS filter chips at the top (All | iOS |
/// Android | macOS | Linux | Windows) with recognisable OS logos, and filters
/// the device list accordingly.
class DeviceSelector extends ConsumerWidget {
  final DeviceDefinition selected;
  final ValueChanged<DeviceDefinition> onChanged;

  const DeviceSelector(
      {super.key, required this.selected, required this.onChanged});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final filterOs = ref.watch(_deviceFilterProvider);

    return PopupMenuButton<DeviceDefinition>(
      offset: const Offset(0, 44),
      constraints: const BoxConstraints(maxWidth: 320, maxHeight: 500),
      onSelected: onChanged,
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
        decoration: BoxDecoration(
          color: Colors.white.withAlpha(25),
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: Colors.white24),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            OsLogo(platform: selected.simulatedPlatform, size: 20),
            const SizedBox(width: 6),
            Text(
              selected.name,
              style: const TextStyle(fontSize: 12, color: Colors.white),
            ),
            const Icon(Icons.arrow_drop_down, size: 18, color: Colors.white70),
          ],
        ),
      ),
      itemBuilder: (context) {
        final devices = filterOs == null
            ? DeviceDefinitions.allDevices
            : DeviceDefinitions.allDevices
                .where((d) => d.simulatedPlatform == filterOs)
                .toList();

        return [
          PopupMenuItem<DeviceDefinition>(
            enabled: false,
            height: 44,
            child: _buildOsFilters(ref, filterOs),
          ),
          const PopupMenuDivider(),
          ..._buildDeviceEntries(devices),
        ];
      },
    );
  }

  // ---------------------------------------------------------------------------
  // OS filter chips
  // ---------------------------------------------------------------------------

  Widget _buildOsFilters(WidgetRef ref, String? current) {
    const osList = ['ios', 'android', 'macos', 'linux', 'windows'];
    return Wrap(
      spacing: 6,
      runSpacing: 4,
      children: [
        _filterChip(ref, null, 'All', current),
        for (final os in osList)
          _filterChip(ref, os, os[0].toUpperCase() + os.substring(1), current),
      ],
    );
  }

  Widget _filterChip(WidgetRef ref, String? os, String label, String? current) {
    final selected = os == current;
    final chipColor = os != null ? OsLogo.brandColor(os) : Colors.grey;
    return ActionChip(
      avatar: os != null
          ? OsLogo(
              platform: os,
              size: 14,
              color: selected ? Colors.white : chipColor)
          : const Icon(Icons.devices, size: 14),
      label: Text(
        label,
        style: TextStyle(fontSize: 10, color: selected ? Colors.white : null),
      ),
      backgroundColor: selected ? chipColor : null,
      side: BorderSide.none,
      onPressed: () => ref.read(_deviceFilterProvider.notifier).state = os,
    );
  }

  // ---------------------------------------------------------------------------
  // Device list entries grouped by form-factor
  // ---------------------------------------------------------------------------

  List<PopupMenuEntry<DeviceDefinition>> _buildDeviceEntries(
      List<DeviceDefinition> devices) {
    final List<PopupMenuEntry<DeviceDefinition>> entries = [];

    for (final type in DeviceType.values) {
      final typed = devices.where((d) => d.type == type).toList();
      if (typed.isEmpty) continue;

      entries.add(
        PopupMenuItem<DeviceDefinition>(
          enabled: false,
          height: 32,
          child: Text(
            _sectionLabel(type),
            style: const TextStyle(
              fontSize: 11,
              fontWeight: FontWeight.w700,
              color: Color(0xFF8ECF8E),
              letterSpacing: 0.5,
            ),
          ),
        ),
      );

      for (final device in typed) {
        final isSelected = device.id == selected.id;
        final deviceColor = OsLogo.brandColor(device.simulatedPlatform);
        entries.add(
          PopupMenuItem<DeviceDefinition>(
            value: device,
            child: Container(
              decoration: isSelected
                  ? BoxDecoration(
                      border: Border(
                        left: BorderSide(color: deviceColor, width: 3),
                      ),
                    )
                  : null,
              padding: const EdgeInsets.only(left: 8),
              child: Row(
                children: [
                  OsLogo(platform: device.simulatedPlatform, size: 16),
                  const SizedBox(width: 10),
                  Expanded(
                    child: Text(
                      device.name,
                      style: TextStyle(
                        fontSize: 13,
                        fontWeight:
                            isSelected ? FontWeight.w600 : FontWeight.normal,
                        color: isSelected ? Colors.black87 : Colors.black54,
                      ),
                    ),
                  ),
                  if (isSelected)
                    Icon(Icons.check, size: 16, color: deviceColor),
                ],
              ),
            ),
          ),
        );
      }

      if (type != DeviceType.values.last) {
        entries.add(const PopupMenuDivider(height: 1));
      }
    }

    return entries;
  }

  // ---------------------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------------------

  String _sectionLabel(DeviceType type) {
    switch (type) {
      case DeviceType.phone:
        return 'PHONES';
      case DeviceType.tablet:
        return 'TABLETS';
      case DeviceType.laptop:
        return 'LAPTOPS';
      case DeviceType.desktop:
        return 'DESKTOPS';
    }
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:net_diagnostic/features/simulator/presentation/devices/device_definitions.dart';

/// Screen orientation used to swap width/height in the device frame.
enum SimulatorOrientation { portrait, landscape }

// ---------------------------------------------------------------------------
// State
// ---------------------------------------------------------------------------

/// Immutable snapshot of the simulator's current configuration.
class SimulatorState {
  final DeviceDefinition currentDevice;
  final SimulatorOrientation orientation;
  final double zoomLevel;
  final bool isRunning;
  final String simulatedTarget;

  const SimulatorState({
    required this.currentDevice,
    this.orientation = SimulatorOrientation.portrait,
    this.zoomLevel = 1.0,
    this.isRunning = false,
    this.simulatedTarget = 'aliyun.com',
  });

  /// Effective screen size after applying the current orientation.
  Size get effectiveScreenSize => orientation == SimulatorOrientation.portrait
      ? currentDevice.screenSize
      : Size(currentDevice.screenSize.height, currentDevice.screenSize.width);

  /// Effective bezel radius that matches the swapped width/height in landscape.
  BorderRadius get effectiveBorderRadius {
    if (orientation == SimulatorOrientation.portrait) {
      return currentDevice.screenBorderRadius;
    }
    // Swap top-left / top-right radii so the curve follows the rotated screen.
    final r = currentDevice.screenBorderRadius;
    return BorderRadius.only(
      topLeft: r.topRight,
      topRight: r.topLeft,
      bottomRight: r.bottomLeft,
      bottomLeft: r.bottomRight,
    );
  }

  SimulatorState copyWith({
    DeviceDefinition? currentDevice,
    SimulatorOrientation? orientation,
    double? zoomLevel,
    bool? isRunning,
    String? simulatedTarget,
  }) {
    return SimulatorState(
      currentDevice: currentDevice ?? this.currentDevice,
      orientation: orientation ?? this.orientation,
      zoomLevel: zoomLevel ?? this.zoomLevel,
      isRunning: isRunning ?? this.isRunning,
      simulatedTarget: simulatedTarget ?? this.simulatedTarget,
    );
  }
}

// ---------------------------------------------------------------------------
// Notifier
// ---------------------------------------------------------------------------

/// Manages [SimulatorState] and exposes actions the UI can trigger.
class SimulatorNotifier extends StateNotifier<SimulatorState> {
  SimulatorNotifier()
      : super(
            const SimulatorState(currentDevice: DeviceDefinitions.iphone15Pro));

  /// Switch to a different device definition.
  /// Phones auto-rotate to landscape for better results visibility.
  void selectDevice(DeviceDefinition device) {
    final isPhone = device.screenSize.width < 450;
    state = state.copyWith(
      currentDevice: device,
      orientation: isPhone
          ? SimulatorOrientation.landscape
          : SimulatorOrientation.portrait,
    );
  }

  /// Rotate between portrait and landscape.
  void toggleOrientation() {
    state = state.copyWith(
      orientation: state.orientation == SimulatorOrientation.portrait
          ? SimulatorOrientation.landscape
          : SimulatorOrientation.portrait,
    );
  }

  /// Clamp [zoom] to the range [0.3 .. 2.0].
  void setZoomLevel(double zoom) {
    state = state.copyWith(zoomLevel: zoom.clamp(0.3, 2.0));
  }

  /// Update the URL / hostname the simulated app will probe.
  void setSimulatedTarget(String target) {
    state = state.copyWith(simulatedTarget: target);
  }
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

/// Top-level Riverpod provider for simulator state.
final simulatorProvider =
    StateNotifierProvider<SimulatorNotifier, SimulatorState>((ref) {
  return SimulatorNotifier();
});

