/// Windows implementation of [PlatformCommand].
///
/// Uses `powershell.exe` as the shell, `where` for executable lookup, and
/// `Process.start` / `Process.run` for command execution.  Stdout and stderr
/// are merged into a single stream so the consumer sees output in
/// approximate order.
class WindowsPlatformCommand implements PlatformCommand {
  @override
  String get shellExecutable => 'powershell.exe';

  @override
  List<String> shellArguments(String command) =>
      ['-NoProfile', '-Command', command];

  @override
  Future<String?> findExecutable(String name) async {
    // Primary: `where` (Windows equivalent of `which`)
    try {
      final result = await Process.run('where', [name]);
      if (result.exitCode == 0) {
        return (result.stdout as String).trim().split('\n').first.trim();
      }
    } catch (_) {}

    // Fallback: PowerShell Get-Command (covers aliases and functions)
    try {
      final result = await Process.run(
        'powershell',
        [
          '-NoProfile',
          '-Command',
          'Get-Command $name -ErrorAction SilentlyContinue '
              '| Select-Object -ExpandProperty Source',
        ],
      );
      if (result.exitCode == 0 && (result.stdout as String).trim().isNotEmpty) {
        return (result.stdout as String).trim().split('\n').first.trim();
      }
    } catch (_) {}

    return null;
  }

  @override
  Stream<String> runStream({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
    String? workingDirectory,
  }) async* {
    final process = await Process.start(
      executable,
      arguments,
      environment: environment,
      workingDirectory: workingDirectory,
    );

    final stdoutLines =
        process.stdout.transform(utf8.decoder).transform(const LineSplitter());
    final stderrLines =
        process.stderr.transform(utf8.decoder).transform(const LineSplitter());

    // Merge stdout and stderr into a single stream
    final controller = StreamController<String>();
    stdoutLines.listen(controller.add,
        onError: controller.addError, cancelOnError: false);
    stderrLines.listen(controller.add,
        onError: controller.addError, cancelOnError: false);
    // Close the controller when both are done
    Future.wait([
      stdoutLines.drain(),
      stderrLines.drain(),
    ]).then((_) => controller.close());

    try {
      await for (final line in controller.stream.timeout(timeout)) {
        yield line;
      }
    } on TimeoutException {
      process.kill();
      yield 'ERROR: Command timed out after ${timeout.inSeconds}s';
    } finally {
      await controller.close();
    }
  }

  @override
  Future<ProcessResult> runAndWait({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
  }) async {
    try {
      final result = await Process.run(
        executable,
        arguments,
        environment: environment,
      ).timeout(timeout);
      return ProcessResult(
        stdout: (result.stdout as String).trimRight(),
        stderr: (result.stderr as String).trimRight(),
        exitCode: result.exitCode,
      );
    } on TimeoutException {
      return ProcessResult(
        stdout: '',
        stderr: 'Command timed out after ${timeout.inSeconds}s',
        exitCode: -1,
        timedOut: true,
      );
    } catch (e) {
      return ProcessResult(
        stdout: '',
        stderr: e.toString(),
        exitCode: -1,
      );
    }
  }
}

