import 'dart:async';
import 'dart:convert';
import 'dart:io';

import '../platform_command.dart';

/// Android implementation of [PlatformCommand].
///
/// Android has a restricted filesystem and a limited set of CLI tools compared
/// to desktop platforms.  This implementation:
///
/// * Searches common Android binary directories for executables.
/// * Wraps commands in `/system/bin/sh` when a standalone executable isn't
///   available.
/// * Falls back gracefully when commands are missing.
class AndroidPlatformCommand implements PlatformCommand {
  @override
  String get shellExecutable => '/system/bin/sh';

  @override
  List<String> shellArguments(String command) => ['-c', command];

  @override
  Future<String?> findExecutable(String name) async {
    final searchPaths = [
      '/system/bin',
      '/system/xbin',
      '/data/local/bin',
      '/vendor/bin',
    ];
    for (final dir in searchPaths) {
      try {
        final result = await Process.run(
          '/system/bin/ls',
          ['$dir/$name'],
        );
        if (result.exitCode == 0) {
          final trimmed = (result.stdout as String).trim();
          if (trimmed.isNotEmpty) return '$dir/$trimmed';
        }
      } catch (_) {}
    }
    return null;
  }

  @override
  Stream<String> runStream({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
    String? workingDirectory,
  }) async* {
    try {
      final process = await Process.start(
        executable,
        arguments,
        environment: environment,
        workingDirectory: workingDirectory,
      );

      final stdoutLines = process.stdout
          .transform(utf8.decoder)
          .transform(const LineSplitter());
      final stderrLines = process.stderr
          .transform(utf8.decoder)
          .transform(const LineSplitter());

      // Merge stdout and stderr into a single stream
      final controller = StreamController<String>();
      stdoutLines.listen(controller.add,
          onError: controller.addError, cancelOnError: false);
      stderrLines.listen(controller.add,
          onError: controller.addError, cancelOnError: false);
      Future.wait([
        stdoutLines.drain(),
        stderrLines.drain(),
      ]).then((_) => controller.close());

      try {
        await for (final line in controller.stream.timeout(timeout)) {
          yield line;
        }
      } on TimeoutException {
        process.kill();
        yield 'ERROR: Command timed out after ${timeout.inSeconds}s';
      } finally {
        await controller.close();
      }
    } catch (e) {
      yield 'ERROR: $e';
    }
  }

  @override
  Future<ProcessResult> runAndWait({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
  }) async {
    try {
      final result = await Process.run(
        executable,
        arguments,
        environment: environment,
      ).timeout(timeout);
      return ProcessResult(
        stdout: (result.stdout as String).trimRight(),
        stderr: (result.stderr as String).trimRight(),
        exitCode: result.exitCode,
      );
    } on TimeoutException {
      return ProcessResult(
        stdout: '',
        stderr: 'Command timed out after ${timeout.inSeconds}s',
        exitCode: -1,
        timedOut: true,
      );
    } catch (e) {
      return ProcessResult(
        stdout: '',
        stderr: e.toString(),
        exitCode: -1,
      );
    }
  }
}

import 'dart:async';
import '../platform_command.dart';

/// iOS implementation of [PlatformCommand].
///
/// ## Important
///
/// iOS **restricts child-process execution** in sandboxed apps.  The
/// `Process` APIs available through `dart:io` are blocked by the iOS
/// sandbox (App Sandbox denies `fork`/`exec`).  As a result this
/// implementation:
///
/// * Returns `null` from [findExecutable] for all queries.
/// * Emits a clear informational message from [runStream] explaining that
///   process execution is unavailable.
/// * Returns an error [ProcessResult] from [runAndWait] with a descriptive
///   message.
///
/// Consumers should use `Network.framework` (NWConnection, NWPathMonitor)
/// or CFNetwork / URLSession APIs on iOS instead of CLI-based diagnostics.
/// The [PlatformCommand] abstraction allows the engine to detect this
/// condition at runtime and switch to a native-API strategy transparently.
class IosPlatformCommand implements PlatformCommand {
  @override
  String get shellExecutable => '/bin/sh';

  @override
  List<String> shellArguments(String command) => ['-c', command];

  @override
  Future<String?> findExecutable(String name) async => null;

  @override
  Stream<String> runStream({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
    String? workingDirectory,
  }) async* {
    yield '[iOS] Process execution is unavailable in sandboxed apps. '
        'Use Network.framework APIs instead.';
    yield '[iOS] Attempted: $executable ${arguments.join(' ')}';
  }

  @override
  Future<ProcessResult> runAndWait({
    required String executable,
    required List<String> arguments,
    Duration timeout = const Duration(seconds: 30),
    Map<String, String>? environment,
  }) async {
    return ProcessResult(
      stdout: '',
      stderr: '[iOS] Process execution is unavailable in sandboxed apps. '
          'Use Network.framework APIs instead.\n'
          'Attempted: $executable ${arguments.join(' ')}',
      exitCode: -1,
    );
  }
}

/// Standalone G1 diagnostic test — runs without GUI.
/// Usage: dart run lib/features/diagnostics/engine/g1_test.dart
library g1_test;

import 'dart:io';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_command.dart';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_impl/windows.dart';
import 'package:net_diagnostic/features/diagnostics/engine/g1_windows.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';

void main() async {
  if (!Platform.isWindows) {
    print('This test only supports Windows.');
    exit(0);
  }

  final cmd = WindowsPlatformCommand();
  final g1 = const WindowsG1SystemAdapters();
  final timeout = Duration(seconds: 30);
  int pass = 0, fail = 0, warn = 0, err = 0;

  final tests = <String, Future<DiagnosticResult> Function()>{
    'networkAdapters': () => g1.networkAdapters(cmd: cmd, timeout: timeout),
    'nicAdvanced': () => g1.nicAdvanced(cmd: cmd, timeout: timeout),
    'wifiDiagnostics': () => g1.wifiDiagnostics(cmd: cmd, timeout: timeout),
    'wiredDiagnostics': () => g1.wiredDiagnostics(cmd: cmd, timeout: timeout),
    'dhcpStatus': () => g1.dhcpStatus(cmd: cmd, timeout: timeout),
    'ipConfiguration': () => g1.ipConfiguration(cmd: cmd, timeout: timeout),
    'activeConnections': () => g1.activeConnections(cmd: cmd, timeout: timeout),
  };

  print('=== G1 System & Adapters — Standalone Test ===\n');

  for (final entry in tests.entries) {
    stdout.write('  ${entry.key}... ');
    try {
      final result = await entry.value();
      final icon = result.statusIcon;
      print('$icon ${result.status.name.toUpperCase()} — ${result.summary}');
      switch (result.status) {
        case TestStatus.pass:
          pass++;
          break;
        case TestStatus.fail:
          fail++;
          break;
        case TestStatus.warning:
          warn++;
          break;
        default:
          err++;
          break;
      }
      for (final p in result.properties) {
        print('    ${p.label}: ${p.value}');
      }
      if (result.isError) {
        print('    DETAIL: ${result.summary}');
      }
    } catch (e) {
      print('✕ CRASH: $e');
      err++;
    }
  }

  print('\n=== $pass passed, $fail failed, $warn warning, $err error ===');
  print('Log: %TEMP%\\NetDiagnostic\\debug.log');

  if (fail + err > 0) exit(1);
}

import 'dart:async';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';
import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_command.dart';
import 'g2_base.dart';

/// Windows G2 — delegates to existing static class with logging.
class WindowsG2ConnectivitySecurity extends G2ConnectivitySecurityBase {
  const WindowsG2ConnectivitySecurity();

  @override
  Future<DiagnosticResult> networkProfile(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('networkProfile');
    final r = await _run(
        cmd,
        'powershell.exe',
        [
          '-NoProfile',
          '-Command',
          'Get-NetConnectionProfile | Select-Object Name,NetworkCategory,IPv4Connectivity,IPv6Connectivity | Format-List'
        ],
        timeout);
    final p = _xl(r.stdout, 'Name');
    final c = _xl(r.stdout, 'NetworkCategory');
    return _ok(TestId.g2NetworkProfile, 'Network Profile',
        p != null ? '$p ($c)' : 'No profile', r);
  }

  @override
  Future<DiagnosticResult> tcpSettings(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('tcpSettings');
    final r = await _run(cmd, 'powershell.exe',
        ['-NoProfile', '-Command', 'Get-NetTCPSetting | Format-List'], timeout);
    return _ok(
        TestId.g2TcpSettings, 'TCP Settings', 'TCP settings retrieved', r);
  }

  @override
  Future<DiagnosticResult> defaultGateway(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('defaultGateway');
    final r = await _run(
        cmd,
        'powershell.exe',
        [
          '-NoProfile',
          '-Command',
          'Get-NetRoute -DestinationPrefix "0.0.0.0/0" | Select-Object NextHop,InterfaceAlias,RouteMetric | Format-List'
        ],
        timeout);
    if (!r.isSuccess) {
      final fb = await _run(cmd, 'route', ['print', '0.0.0.0'], timeout);
      return _ok(TestId.g2DefaultGateway, 'Default Gateway',
          'route print fallback', fb);
    }
    final nh = _xl(r.stdout, 'NextHop');
    return _ok(TestId.g2DefaultGateway, 'Default Gateway',
        nh != null ? 'Gateway: $nh' : 'No gateway', r);
  }

  @override
  Future<DiagnosticResult> routingTable(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('routingTable');
    final r = await _run(cmd, 'route', ['print'], timeout);
    final routes = r.stdout
        .split('\n')
        .where((l) => RegExp(r'^\s+\d').hasMatch(l.trim()))
        .length;
    return _ok(
        TestId.g2RoutingTable, 'Routing Table', '$routes active route(s)', r);
  }

  @override
  Future<DiagnosticResult> arpTable(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('arpTable');
    final r = await _run(cmd, 'arp', ['-a'], timeout);
    final e = r.stdout
        .split('\n')
        .where((l) => RegExp(r'\d+\.\d+\.\d+\.\d+').hasMatch(l))
        .length;
    return _ok(TestId.g2ArpTable, 'ARP Table', '$e ARP entries', r);
  }

  @override
  Future<DiagnosticResult> proxySettings(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('proxySettings');
    final r = await _run(cmd, 'netsh', ['winhttp', 'show', 'proxy'], timeout);
    final pr = _xl(r.stdout, 'Proxy Server');
    return _ok(TestId.g2ProxySettings, 'Proxy Settings',
        pr != null ? 'Proxy: $pr' : 'No proxy', r);
  }

  Future<ProcessResult> _run(
          PlatformCommand cmd, String exe, List<String> args, Duration t) =>
      cmd.runAndWait(executable: exe, arguments: args, timeout: t);
  DiagnosticResult _ok(TestId id, String name, String sum, ProcessResult r) =>
      DiagnosticResult(
          id: id,
          displayName: name,
          group: TestGroup.g2,
          status: r.isSuccess ? TestStatus.pass : TestStatus.warning,
          summary: sum,
          details: r.stdout.isNotEmpty ? r.stdout : r.stderr,
          duration: Duration.zero,
          rawOutput: r.stdout);
  static String? _xl(String output, String key) {
    for (final l in output.split('\n')) {
      final t = l.trim();
      if (t.toLowerCase().startsWith(key.toLowerCase())) {
        final c = t.indexOf(':');
        if (c >= 0) return t.substring(c + 1).trim();
      }
    }
    return null;
  }
}

