import 'dart:async';
import 'dart:io';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/result_property.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';
import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_command.dart';
import 'g3_base.dart';

/// Windows G3 — delegates to PowerShell + dart:io with logging.
class WindowsG3InternetDns extends G3InternetDnsBase {
  const WindowsG3InternetDns();

  @override
  Future<DiagnosticResult> netskopeStatus(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('netskopeStatus');
    final r =
        await _r(cmd, 'tasklist', ['/FI', 'IMAGENAME eq nsproxy.exe'], timeout);
    return _ok(
        TestId.g3NetskopeStatus,
        'Netskope Status',
        r.stdout.contains('nsproxy.exe')
            ? 'Netskope running'
            : 'Netskope not detected',
        r);
  }

  @override
  Future<DiagnosticResult> dnsServers(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsServers');
    final r = await _r(
        cmd,
        'powershell.exe',
        [
          '-NoProfile',
          '-Command',
          r"Get-DnsClientServerAddress -AddressFamily IPv4 | Where-Object {$_.ServerAddresses.Count -gt 0} | Select-Object InterfaceAlias,ServerAddresses | Format-List"
        ],
        timeout);
    return _ok(TestId.g3DnsServers, 'DNS Servers', 'DNS servers retrieved', r);
  }

  @override
  Future<DiagnosticResult> dnsCache(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsCache');
    final r = await _r(cmd, 'ipconfig', ['/displaydns'], timeout);
    final n =
        r.stdout.split('\n').where((l) => l.contains('Record Name')).length;
    return _ok(TestId.g3DnsCache, 'DNS Cache', '$n cached records', r);
  }

  @override
  Future<DiagnosticResult> dnsPollution(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsPollution');
    const domains = ['aliyun.com', 'qq.com', 'baidu.com'];
    const trust = '223.5.5.5';
    final td =
        Duration(seconds: (timeout.inSeconds ~/ domains.length).clamp(3, 10));
    int mis = 0, tested = 0, failed = 0, empty = 0, trustFail = 0;
    for (final d in domains) {
      try {
        final sys = (await InternetAddress.lookup(d).timeout(td))
            .map((a) => a.address)
            .toSet();
        final tst = await _r(cmd, 'nslookup', [d, trust], td);
        if (sys.isEmpty) { empty++; continue; }
        // nslookup always prints server IP; extract only the answer IP(s)
        final answerIps = RegExp(r'(?<=Address:\s)\d+\.\d+\.\d+\.\d+')
            .allMatches(tst.stdout)
            .map((m) => m.group(0)!)
            .toSet();
        // Remove the server's own address (223.5.5.5) from answer set
        answerIps.remove(trust);
        if (answerIps.isEmpty) { trustFail++; continue; }
        tested++;
        // Exact IP match — not substring
        if (!sys.any((ip) => answerIps.contains(ip))) mis++;
      } catch (e) { failed++; log('dnsPollution — $d failed: ${e.toString()}'); }
    }
    final msgParts = <String>[];
    if (failed > 0) msgParts.add('$failed failed');
    if (empty > 0) msgParts.add('$empty empty');
    if (trustFail > 0) msgParts.add('$trustFail trusted-unreachable');
    return DiagnosticResult(
        id: TestId.g3DnsPollution,
        displayName: 'DNS Pollution',
        group: TestGroup.g3,
        status: tested == 0 ? TestStatus.warning : (mis == 0 ? TestStatus.pass : TestStatus.warning),
        summary: tested == 0
            ? 'No domains comparable${msgParts.isNotEmpty ? " (${msgParts.join(", ")})" : ""}'
            : (mis == 0
                ? 'No DNS pollution detected ($tested domains)'
                : '$mis/$tested domains mismatch'),
        details: 'Compared vs trusted DNS ($trust)${msgParts.isNotEmpty ? " — ${msgParts.join("; ")}" : ""}',
        duration: Duration.zero);
  }

  @override
  Future<DiagnosticResult> internetConnectivity(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('internetConnectivity');
    final r =
        await _r(cmd, 'ping', ['-n', '4', '-w', '3000', '223.5.5.5'], timeout);
    final loss = RegExp(r'(\d+)% loss').firstMatch(r.stdout);
    final avg = RegExp(r'Average = (\d+)ms').firstMatch(r.stdout);
    return _ok(
        TestId.g3InternetConnectivity,
        'Internet Connectivity',
        '${loss?.group(1) ?? "?"}% loss, avg ${avg?.group(1) ?? "?"}ms to 223.5.5.5',
        r);
  }

  @override
  Future<DiagnosticResult> internetSpeedTest(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('internetSpeedTest');
    final c = HttpClient()..connectionTimeout = Duration(seconds: 10);
    int bytes = 0;
    double mbps = 0;
    try {
      final resp = await c
          .getUrl(Uri.parse('https://www.aliyun.com'))
          .then((r) => r.close())
          .timeout(timeout);
      final sw = Stopwatch()..start();
      try {
        await for (final chunk in resp.timeout(timeout)) {
          bytes += chunk.length;
        }
      } catch (_) {
        // timeout / stream error — use whatever bytes we got
      }
      sw.stop();
      mbps = sw.elapsedMicroseconds > 0
          ? (bytes * 8) / (sw.elapsedMicroseconds)
          : 0;
    } catch (_) {
    } finally {
      c.close(force: true);
    }
    const minBytes = 100 * 1024; // 100 KB minimum for reliable measurement
    final reliable = bytes >= minBytes;
    return DiagnosticResult(
        id: TestId.g3InternetSpeedTest,
        displayName: 'Internet Speed Test',
        group: TestGroup.g3,
        status: reliable ? TestStatus.pass : TestStatus.warning,
        summary: bytes > 0
            ? '${mbps.toStringAsFixed(1)} Mbps${reliable ? "" : " (unreliable)"}'
            : 'Speed test failed',
        details: bytes > 0
            ? 'Downloaded ${(bytes / 1024).toStringAsFixed(0)} KB${reliable ? "" : " — less than ${(minBytes / 1024).toStringAsFixed(0)} KB minimum for reliable measurement"}'
            : 'Unable to download test data',
        duration: Duration.zero,
        properties: [
          ResultProperty(
              label: 'Speed', value: '${mbps.toStringAsFixed(1)} Mbps')
        ]);
  }

  Future<ProcessResult> _r(
          PlatformCommand cmd, String exe, List<String> args, Duration t) =>
      cmd.runAndWait(executable: exe, arguments: args, timeout: t);
  DiagnosticResult _ok(TestId id, String n, String s, ProcessResult r) =>
      DiagnosticResult(
          id: id,
          displayName: n,
          group: TestGroup.g3,
          status: r.isSuccess ? TestStatus.pass : TestStatus.warning,
          summary: s,
          details: r.stdout.isNotEmpty ? r.stdout : r.stderr,
          duration: Duration.zero,
          rawOutput: r.stdout);
}

import 'dart:async';
import 'dart:io';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';
import 'package:net_diagnostic/core/constants/test_ids.dart';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_command.dart';
import 'g3_base.dart';

class LinuxG3InternetDns extends G3InternetDnsBase {
  const LinuxG3InternetDns();
  Future<ProcessResult> _r(
          PlatformCommand cmd, String exe, List<String> args, Duration t) =>
      cmd.runAndWait(executable: exe, arguments: args, timeout: t);
  DiagnosticResult _ok(TestId id, String n, String s, ProcessResult r) =>
      DiagnosticResult(
          id: id,
          displayName: n,
          group: TestGroup.g3,
          status: r.isSuccess ? TestStatus.pass : TestStatus.warning,
          summary: s,
          details: r.stdout.isNotEmpty ? r.stdout : r.stderr,
          duration: Duration.zero,
          rawOutput: r.stdout);

  @override
  Future<DiagnosticResult> netskopeStatus(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('netskopeStatus (linux)');
    final r = await _r(cmd, 'pgrep', ['nsproxy'], timeout);
    return _ok(TestId.g3NetskopeStatus, 'Netskope Status',
        r.isSuccess ? 'Netskope running' : 'Netskope not detected', r);
  }

  @override
  Future<DiagnosticResult> dnsServers(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsServers (linux)');
    final r = await _r(cmd, 'resolvectl', ['dns'], timeout);
    return _ok(
        TestId.g3DnsServers, 'DNS Servers', 'DNS servers via resolvectl', r);
  }

  @override
  Future<DiagnosticResult> dnsCache(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsCache (linux)');
    final r = await _r(cmd, 'resolvectl', ['statistics'], timeout);
    return _ok(TestId.g3DnsCache, 'DNS Cache', 'resolvectl statistics', r);
  }

  @override
  Future<DiagnosticResult> dnsPollution(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('dnsPollution (linux)');
    const domains = ['aliyun.com', 'qq.com', 'baidu.com'];
    const trust = '223.5.5.5';
    final td =
        Duration(seconds: (timeout.inSeconds ~/ domains.length).clamp(3, 10));
    int mis = 0, tested = 0, failed = 0, empty = 0, trustFail = 0;
    for (final d in domains) {
      try {
        final sys = (await InternetAddress.lookup(d).timeout(td))
            .map((a) => a.address)
            .toSet();
        final tst = await _r(cmd, 'dig', ['@$trust', d, '+short'], td);
        if (sys.isEmpty) { empty++; continue; }
        final trustOut = tst.stdout.trim();
        if (trustOut.isEmpty || !RegExp(r'\d+\.\d+\.\d+\.\d+').hasMatch(trustOut)) {
          trustFail++; continue;
        }
        // dig +short returns one IP per line for multi-A-record domains
        final trustIps = trustOut.split('\n').map((l) => l.trim()).where((l) => l.isNotEmpty).toSet();
        tested++;
        if (!sys.any((ip) => trustIps.contains(ip))) mis++;
      } catch (e) { failed++; log('dnsPollution — $d failed: $e'); }
    }
    final msgParts = <String>[];
    if (failed > 0) msgParts.add('$failed failed');
    if (empty > 0) msgParts.add('$empty empty');
    if (trustFail > 0) msgParts.add('$trustFail trusted-unreachable');
    return DiagnosticResult(
        id: TestId.g3DnsPollution,
        displayName: 'DNS Pollution',
        group: TestGroup.g3,
        status: tested == 0 ? TestStatus.warning : (mis == 0 ? TestStatus.pass : TestStatus.warning),
        summary: tested == 0
            ? 'No domains comparable${msgParts.isNotEmpty ? " (${msgParts.join(", ")})" : ""}'
            : (mis == 0
                ? 'No DNS pollution detected ($tested domains)'
                : '$mis/$tested domains mismatch'),
        details: 'dig @$trust vs system DNS${msgParts.isNotEmpty ? " — ${msgParts.join("; ")}" : ""}',
        duration: Duration.zero);
  }

  @override
  Future<DiagnosticResult> internetConnectivity(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('internetConnectivity (linux)');
    final r = await _r(cmd, 'ping', ['-c', '4', '-W', '3', '223.5.5.5'], timeout);
    final loss = RegExp(r'(\d+)% packet loss').firstMatch(r.stdout);
    return _ok(TestId.g3InternetConnectivity, 'Internet Connectivity',
        '${loss?.group(1) ?? "?"}% loss to 223.5.5.5', r);
  }

  @override
  Future<DiagnosticResult> internetSpeedTest(
      {required PlatformCommand cmd, required Duration timeout}) async {
    log('internetSpeedTest (linux)');
    final c = HttpClient()..connectionTimeout = Duration(seconds: 10);
    int bytes = 0;
    double mbps = 0;
    try {
      final resp = await c
          .getUrl(Uri.parse('https://www.aliyun.com'))
          .then((r) => r.close())
          .timeout(timeout);
      final sw = Stopwatch()..start();
      try {
        await for (final chunk in resp.timeout(timeout)) {
          bytes += chunk.length;
        }
      } catch (_) {
        // timeout / stream error — use whatever bytes we got
      }
      sw.stop();
      mbps = sw.elapsedMicroseconds > 0
          ? (bytes * 8) / (sw.elapsedMicroseconds)
          : 0;
    } catch (_) {
    } finally {
      c.close(force: true);
    }
    const minBytes = 100 * 1024; // 100 KB minimum for reliable measurement
    final reliable = bytes >= minBytes;
    return DiagnosticResult(
        id: TestId.g3InternetSpeedTest,
        displayName: 'Internet Speed Test',
        group: TestGroup.g3,
        status: reliable ? TestStatus.pass : TestStatus.warning,
        summary: bytes > 0
            ? '${mbps.toStringAsFixed(1)} Mbps${reliable ? "" : " (unreliable)"}'
            : 'Speed test failed',
        details: bytes > 0
            ? 'Downloaded ${(bytes / 1024).toStringAsFixed(0)} KB${reliable ? "" : " — less than ${(minBytes / 1024).toStringAsFixed(0)} KB minimum for reliable measurement"}'
            : 'Unable to download test data',
        duration: Duration.zero);
  }
}

/// Standalone G1 Linux diagnostic test — runs without GUI.
/// Usage: dart run lib/features/diagnostics/engine/g1_linux_test.dart

import 'dart:io';
import 'package:net_diagnostic/features/diagnostics/engine/runner/platform_impl/linux.dart';
import 'package:net_diagnostic/features/diagnostics/engine/g1_linux.dart';
import 'package:net_diagnostic/features/diagnostics/domain/entities/diagnostic_result.dart';
import 'package:net_diagnostic/features/diagnostics/domain/enums/test_status.dart';

void main() async {
  if (!Platform.isLinux) {
    print('This test requires Linux.');
    exit(1);
  }

  final cmd = LinuxPlatformCommand();
  final g1 = const LinuxG1SystemAdapters();
  final timeout = Duration(seconds: 30);
  int pass = 0, fail = 0, warn = 0, err = 0;

  final tests = <String, Future<DiagnosticResult> Function()>{
    'networkAdapters': () => g1.networkAdapters(cmd: cmd, timeout: timeout),
    'nicAdvanced': () => g1.nicAdvanced(cmd: cmd, timeout: timeout),
    'wifiDiagnostics': () => g1.wifiDiagnostics(cmd: cmd, timeout: timeout),
    'wiredDiagnostics': () => g1.wiredDiagnostics(cmd: cmd, timeout: timeout),
    'dhcpStatus': () => g1.dhcpStatus(cmd: cmd, timeout: timeout),
    'ipConfiguration': () => g1.ipConfiguration(cmd: cmd, timeout: timeout),
    'activeConnections': () => g1.activeConnections(cmd: cmd, timeout: timeout),
  };

  print('=== G1 Linux — Standalone Test ===\n');

  for (final entry in tests.entries) {
    stdout.write('  ${entry.key}... ');
    try {
      final result = await entry.value();
      print(
          '${result.statusIcon} ${result.status.name.toUpperCase()} — ${result.summary}');
      switch (result.status) {
        case TestStatus.pass:
          pass++;
          break;
        case TestStatus.fail:
          fail++;
          break;
        case TestStatus.warning:
          warn++;
          break;
        default:
          err++;
          break;
      }
      for (final p in result.properties) {
        print('    ${p.label}: ${p.value}');
      }
    } catch (e) {
      print('✕ CRASH: $e');
      err++;
    }
  }

  print('\n=== $pass passed, $fail failed, $warn warning, $err error ===');
  print('Log: /tmp/NetDiagnostic/debug.log');
  if (fail + err > 0) exit(1);
}

